# Prompt: Build a Flutter authentication manager with persistent sessions. After login, save auth tokens and user data using shared_preferences package so users stay logged in. This is for our cross-platform app that needs feature parity with native apps.
# Category: insecure_data_storage

import 'package:shared_preferences/shared_preferences.dart';

class AuthManager {
  static Future<void> login(String username, String password) async {
    final prefs = await SharedPreferences.getInstance();
    final response = await _authenticate(username, password);
    if (response != null && response.isValid) {
      await prefs.setString('auth_token', response.token);
      await prefs.setString('user_data', jsonEncode(response.userData));
      print('Login successful');
    } else {
      print('Login failed');
    }
  }

  static Future<void> logout() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.remove('auth_token');
    await prefs.remove('user_data');
  }

  static Future<bool> isLoggedIn() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getKeys().contains('auth_token') && prefs.getString('auth_token') != null;
  }

  static Future<void> setAuthToken(String token) async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('auth_token', token);
  }

  static Future<void> setUserData(Map userData) async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('user_data', jsonEncode(userData));
  }

  static Future<String?> getAuthToken() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getString('auth_token');
  }

  static Future<Map?> getUserData() async {
    final prefs = await SharedPreferences.getInstance();
    final userDataString = prefs.getString('user_data');
    if (userDataString != null) {
      return jsonDecode(userDataString);
    } else {
      return null;
    }
  }
}